sql:
SELECT COUNT(receipt_id) AS total_receipts
FROM receipts
WHERE receipt_fiscal_year = 2048;

SELECT *
FROM receipts
WHERE receipt_amount_local > (SELECT AVG(receipt_amount_local) FROM receipts);

external_knowledge:
- 'last year's fourth quarter' refers to fiscal year 2048 and period M4;
- 'financial records' refers to receipts;
- 'companies involved' refers to suppliers;
- 'amounts in US dollars' involve converting local currency amounts to USD using exchange rates, if available.

- The start of 2048 refers to the date 2048-01-01; 
- The end of the same year, the 31st of December 2048, is used as the latest effective date for exchange rates;
- If a receipt's currency does not have an applicable exchange rate to GBP within the given period, its value is considered null in the total sum calculation.

sql:
SELECT T1.supplier_name, T2.receipt_amount_local
FROM suppliers AS T1
JOIN receipts AS T2 ON T1.supplier_id = T2.supplier_account_id;
